/// Blit the sovereign diamond logo centered at (cx, cy).
pub fn blit_logo(x: u32, y: u32) {
    blit_raw(&LOGO_PIXELS, LOGO_W, LOGO_H, x, y);
}

/// Blit a raw ARGB pixel slice to the framebuffer with alpha blending.
pub fn blit_raw(pixels: &[u32], w: u32, h: u32, dx: u32, dy: u32) {
    use crate::framebuffer::{FRAMEBUFFER, WIDTH, HEIGHT};
    unsafe {
        let fb = core::ptr::addr_of_mut!(FRAMEBUFFER) as *mut u32;
        let mut row = 0u32;
        while row < h {
            let py = dy + row;
            if (py as usize) >= HEIGHT { break; }
            let mut col = 0u32;
            while col < w {
                let px = dx + col;
                if (px as usize) < WIDTH {
                    let src = pixels[(row * w + col) as usize];
                    let alpha = src >> 24;
                    if alpha > 0 {
                        let offset = py as usize * WIDTH + px as usize;
                        if alpha == 0xFF {
                            core::ptr::write_volatile(fb.add(offset), src & 0x00FF_FFFF);
                        } else {
                            let bg = core::ptr::read_volatile(fb.add(offset));
                            let a = alpha;
                            let na = 255 - a;
                            let r = ((src>>16&0xFF)*a + (bg>>16&0xFF)*na)/255;
                            let g = ((src>>8&0xFF)*a + (bg>>8&0xFF)*na)/255;
                            let b = ((src&0xFF)*a + (bg&0xFF)*na)/255;
                            core::ptr::write_volatile(fb.add(offset), (r<<16)|(g<<8)|b);
                        }
                    }
                }
                col += 1;
            }
            row += 1;
        }
    }
}